// Pick and lock one REQUESTED scenes job from Jobs table.
// Normalize dialogue-first shorts into a shared conversational manifest for scenes/images.

const ARTIFACT = 'scenes';
const LOCK_MIN = 15;
const MAX_RETRIES = 3;
const now = new Date();

function normalizeSpeaker(input) {
  const normalized = String(input || '')
    .trim()
    .toUpperCase()
    .replace(/[^A-Z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '');

  switch (normalized) {
    case 'SAM':
    case 'HOST':
    case 'MODERATOR':
      return 'SAM';
    case 'ALEX':
    case 'GEN_X':
    case 'GENX':
    case 'GEN_XER':
    case 'GENXER':
      return 'ALEX';
    case 'JORDAN':
    case 'MILLENNIAL':
    case 'MILLENNIALS':
      return 'JORDAN';
    case 'RILEY':
    case 'GEN_Z':
    case 'GENZ':
    case 'ZOOMER':
      return 'RILEY';
    default:
      return '';
  }
}

function cleanText(input) {
  return String(input || '').replace(/\s+/g, ' ').trim();
}

function parseNarrationScript(raw) {
  let parsed;
  try {
    parsed = JSON.parse(String(raw || '').trim());
  } catch (error) {
    throw new Error('[Pick scenes] narration_script is not valid JSON: ' + error.message);
  }

  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed) && Object.prototype.hasOwnProperty.call(parsed, 'format_version')) {
    if (parsed.format_version !== 'shorts_dialogue_v2') {
      throw new Error('[Pick scenes] Unsupported narration_script format_version: ' + String(parsed.format_version || ''));
    }
    if (!Array.isArray(parsed.dialogue)) {
      throw new Error('[Pick scenes] shorts_dialogue_v2 narration_script is missing a valid dialogue array.');
    }
    return parsed.dialogue;
  }

  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed) && Array.isArray(parsed.dialogue)) {
    return parsed.dialogue;
  }

  if (Array.isArray(parsed)) {
    return parsed;
  }

  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    if (
      Object.prototype.hasOwnProperty.call(parsed, 'hook') ||
      Object.prototype.hasOwnProperty.call(parsed, 'gen_x') ||
      Object.prototype.hasOwnProperty.call(parsed, 'millennial') ||
      Object.prototype.hasOwnProperty.call(parsed, 'gen_z') ||
      Object.prototype.hasOwnProperty.call(parsed, 'closer')
    ) {
      return [
        { speaker: 'SAM', text: parsed.hook },
        { speaker: 'ALEX', text: parsed.gen_x ?? parsed.genx ?? parsed.alex },
        { speaker: 'JORDAN', text: parsed.millennial ?? parsed.jordan },
        { speaker: 'RILEY', text: parsed.gen_z ?? parsed.genz ?? parsed.riley },
        { speaker: 'SAM', text: parsed.closer }
      ];
    }
  }

  throw new Error('[Pick scenes] narration_script does not match shorts_dialogue_v2 or supported fallback structures.');
}

function normalizeDialogue(rawSegments) {
  if (!Array.isArray(rawSegments)) {
    throw new Error('[Pick scenes] Expected narration segments array after parsing.');
  }

  const normalized = [];
  for (const rawSegment of rawSegments) {
    if (rawSegment == null) continue;

    let speaker = '';
    let text = '';

    if (typeof rawSegment === 'string') {
      text = cleanText(rawSegment);
    } else if (typeof rawSegment === 'object' && !Array.isArray(rawSegment)) {
      speaker = normalizeSpeaker(rawSegment.speaker ?? rawSegment.role ?? rawSegment.character ?? rawSegment.name);
      text = cleanText(rawSegment.text ?? rawSegment.line ?? rawSegment.dialogue ?? rawSegment.content ?? rawSegment.value);
    }

    if (!text) continue;
    if (!speaker) {
      throw new Error('[Pick scenes] Found dialogue line with unknown or missing speaker: "' + text.slice(0, 80) + '"');
    }

    normalized.push({
      segment_index: normalized.length,
      speaker,
      text
    });
  }

  if (!normalized.length) {
    throw new Error('[Pick scenes] Normalized dialogue is empty after trimming empty lines.');
  }

  return normalized;
}

function classifyBeat(segment, index, segments) {
  const text = String(segment.text || '').toLowerCase();
  if (index === segments.length - 1) return 'payoff';
  if (segment.speaker === 'SAM') return 'host_transition';
  if (index > 0 && segments[index - 1].speaker === segment.speaker) return 'same_speaker_continuation';
  if (/(anyway|meanwhile|different|instead|switching gears|hold on|back up)/.test(text)) return 'topic_shift';
  return 'reaction_reply';
}

function buildScenePlan(dialogue) {
  let grouped = [];
  let current = [0];

  for (let i = 1; i < dialogue.length; i++) {
    const prev = dialogue[i - 1];
    const currentSegment = dialogue[i];
    const isLast = i === dialogue.length - 1;
    const sameSpeaker = currentSegment.speaker === prev.speaker;
    const hostTurn = currentSegment.speaker === 'SAM';
    const topicShift = /(anyway|meanwhile|different|instead|switching gears|hold on|back up)/i.test(currentSegment.text);
    const shouldStartNewScene = hostTurn || isLast || topicShift || (!sameSpeaker && current.length >= 2);

    if (shouldStartNewScene) {
      grouped.push(current);
      current = [i];
    } else {
      current.push(i);
    }
  }
  grouped.push(current);

  while (grouped.length < 3) {
    const splitIndex = grouped.findIndex(function(group) { return group.length > 1; });
    if (splitIndex === -1) break;
    const source = grouped[splitIndex];
    grouped.splice(splitIndex, 1, [source[0]], source.slice(1));
  }

  while (grouped.length > 6) {
    const source = grouped.pop();
    grouped[grouped.length - 1] = grouped[grouped.length - 1].concat(source);
  }

  return grouped.map(function(group, sceneIndex) {
    const firstSegment = dialogue[group[0]];
    const lastSegment = dialogue[group[group.length - 1]];
    const beatType = sceneIndex === grouped.length - 1
      ? 'payoff'
      : (firstSegment.speaker === 'SAM'
        ? 'host_transition'
        : (group.length > 1 && firstSegment.speaker === lastSegment.speaker
          ? 'same_speaker_continuation'
          : classifyBeat(lastSegment, group[group.length - 1], dialogue)));

    const chapterLabel = beatType === 'host_transition'
      ? (sceneIndex === 0 ? 'Setup' : 'Reframe')
      : beatType === 'payoff'
        ? 'Payoff'
        : beatType === 'topic_shift'
          ? 'Shift'
          : beatType === 'same_speaker_continuation'
            ? 'Build'
            : 'Reaction';

    return {
      index: sceneIndex,
      related_segment_indexes: group,
      beat_type: beatType,
      chapter_label: chapterLabel,
      position: beatType === 'host_transition' || beatType === 'payoff' ? 'center' : 'bottom',
      bg_index: beatType === 'host_transition' ? 0 : (sceneIndex % 4),
      visual_change_required: beatType === 'host_transition' || beatType === 'topic_shift' || beatType === 'payoff' || group.length > 1,
      speaker_focus: group.map(function(segIdx) { return dialogue[segIdx].speaker; }).filter(function(v, i, a) { return a.indexOf(v) === i; }),
      reaction_intensity: beatType === 'reaction_reply' || beatType === 'payoff' ? 'high' : beatType === 'host_transition' ? 'low' : 'medium',
      visual_priority: beatType === 'host_transition' ? 'text' : beatType === 'reaction_reply' || beatType === 'payoff' ? 'speaker' : 'split'
    };
  });
}

const candidates = items.filter(function(item) {
  const j = item.json;
  if (j[ARTIFACT + '_state'] !== 'REQUESTED') return false;
  if (j.qa_approved !== true) return false;
  if (j.lifecycle_state !== 'ACTIVE') return false;
  const lu = j.lock_until ? new Date(j.lock_until) : null;
  if (lu && lu > now) return false;
  if (parseInt(j.retry_count || '0', 10) >= MAX_RETRIES) return false;
  return true;
});

if (candidates.length === 0) {
  throw new Error('[Pick ' + ARTIFACT + '] No unlocked REQUESTED jobs under retry limit.');
}

const row = candidates[0].json;

// Priority 1: turns_json as primary dialogue source
let normalizedDialogue = null;
let dialogueSource = '';
const rawTurnsJson = String(row.turns_json || '').trim();
if (rawTurnsJson) {
  try {
    const parsedTurns = JSON.parse(rawTurnsJson);
    if (Array.isArray(parsedTurns) && parsedTurns.length > 0) {
      normalizedDialogue = normalizeDialogue(parsedTurns);
      dialogueSource = 'turns_json';
    }
  } catch (turnsErr) {
    // turns_json malformed - fall through to narration_script
  }
}

// Priority 2: narration_script legacy fallback
if (!normalizedDialogue) {
  const narrationScriptRaw = String(row.narration_script || '').trim();
  if (!narrationScriptRaw) {
    throw new Error(
      '[Pick scenes] No valid dialogue source for job_id: ' + row.job_id + '.\n' +
      'turns_json was absent or invalid and narration_script is empty.\n' +
      'Re-run the "Topic to Script" workflow for this topic.'
    );
  }
  normalizedDialogue = normalizeDialogue(parseNarrationScript(narrationScriptRaw));
  dialogueSource = 'narration_script';
}

// Beat context: prefer beats_json over derived scene plan
let scenePlan = null;
const rawBeatsJson = String(row.beats_json || '').trim();
if (rawBeatsJson) {
  try {
    const parsedBeats = JSON.parse(rawBeatsJson);
    if (Array.isArray(parsedBeats) && parsedBeats.length >= 3 && parsedBeats.length <= 6) {
      scenePlan = parsedBeats.map(function(beat, i) {
        const rawIdx = beat.beat_index != null ? beat.beat_index : (beat.index != null ? beat.index : i);
        const idx = Number(rawIdx);
        return {
          index: Number.isInteger(idx) ? idx : i,
          related_segment_indexes: Array.isArray(beat.related_segment_indexes) ? beat.related_segment_indexes : [i],
          beat_type: String(beat.beat_type || 'reaction_reply'),
          chapter_label: String(beat.chapter_label || ''),
          position: String(beat.position || ((beat.beat_type === 'host_transition' || beat.beat_type === 'payoff') ? 'center' : 'bottom')),
          bg_index: Number.isInteger(Number(beat.bg_index)) ? Number(beat.bg_index) : (i % 4),
          visual_change_required: beat.visual_change_required != null ? Boolean(beat.visual_change_required) : true,
          speaker_focus: Array.isArray(beat.speaker_focus) ? beat.speaker_focus : [],
          reaction_intensity: String(beat.reaction_intensity || 'medium'),
          visual_priority: String(beat.visual_priority || 'split')
        };
      });
    }
  } catch (beatsErr) {
    // beats_json malformed - fall through to derived scene plan
  }
}

if (!scenePlan) {
  scenePlan = buildScenePlan(normalizedDialogue);
}

if (scenePlan.length < 3 || scenePlan.length > 6) {
  throw new Error('[Pick scenes] Derived scene plan must contain 3 to 6 scenes, got ' + scenePlan.length + '.');
}

// Optional packaging cues (read-only, never throw on missing or malformed)
const hookLine = String(row.hook_line || '').trim();
const titleMoment = String(row.title_moment || '').trim();
let visualMomentTagsSummary = '';
const rawVisualMomentTags = String(row.visual_moment_tags_json || '').trim();
if (rawVisualMomentTags) {
  try {
    const parsedTags = JSON.parse(rawVisualMomentTags);
    if (Array.isArray(parsedTags) && parsedTags.length > 0) {
      visualMomentTagsSummary = parsedTags.slice(0, 5).join(', ');
    } else if (parsedTags && typeof parsedTags === 'object') {
      visualMomentTagsSummary = Object.values(parsedTags)
        .reduce(function(a, v) { return a.concat(Array.isArray(v) ? v : [v]); }, [])
        .slice(0, 5).join(', ');
    }
  } catch (tagsErr) {
    // ignore silently
  }
}

const narrationScript = String(row.narration_script || '').trim();
const wordCount = normalizedDialogue.reduce(function(total, segment) {
  return total + segment.text.split(/\s+/).filter(Boolean).length;
}, 0);

const sheetDur = Number(row.estimated_duration_sec) || 0;
const estimatedDurationSec = sheetDur > 0
  ? sheetDur
  : Math.max(8, Math.round(wordCount / 2.6));
const durationSource = sheetDur > 0 ? 'sheet' : 'dialogue_word_count';

const topic = String(row.topic || '').trim();
const fallbackSlug = topic
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .slice(0, 60) || 'topic';
const slug = String(row.slug || fallbackSlug).trim() || fallbackSlug;

const lockUntil = new Date(now.getTime() + LOCK_MIN * 60000).toISOString();
const lockOwner = ($execution && $execution.id) ? $execution.id : ('n8n-' + Date.now());

return [{
  json: {
    job_id: String(row.job_id || '').trim(),
    topic: topic,
    angle: String(row.angle || '').trim(),
    niche: String(row.niche || 'generational_slang').trim(),
    slug: slug,
    topic_slug: slug,
    narration_script: narrationScript,
    chapters_json: String(row.chapters_json || '[]').trim(),
    normalized_dialogue_json: JSON.stringify(normalizedDialogue),
    scene_plan_json: JSON.stringify(scenePlan),
    word_count: wordCount,
    segment_count: normalizedDialogue.length,
    estimated_duration_sec: estimatedDurationSec,
    duration_source: durationSource,
    dialogue_source: dialogueSource,
    hook_line: hookLine,
    title_moment: titleMoment,
    visual_moment_tags_summary: visualMomentTagsSummary,
    scenes_filename: slug + '_scenes.json',
    images_filename: slug + '_images.json',
    _lock_until: lockUntil,
    _lock_owner: lockOwner,
    _retry_count: parseInt(row.retry_count || '0', 10)
  }
}];

// Build the OpenAI request payload for beat-aware scenes JSON generation.
// system = prompt_canon_header; user = prompt_shorts_scenes with placeholder substitution.

const config = $('Code: Build Config').first().json;
const jobConfig = $('Code: Pick & Lock Job').first().json;

let normalizedDialogue;
let scenePlan;
try {
  normalizedDialogue = JSON.parse(String(jobConfig.normalized_dialogue_json || '[]'));
  scenePlan = JSON.parse(String(jobConfig.scene_plan_json || '[]'));
} catch (error) {
  throw new Error('[Build Scenes Prompt] Failed to parse normalized dialogue or scene plan: ' + error.message);
}

if (!Array.isArray(normalizedDialogue) || !normalizedDialogue.length) {
  throw new Error('[Build Scenes Prompt] normalized_dialogue_json is empty or invalid.');
}
if (!Array.isArray(scenePlan) || scenePlan.length < 3 || scenePlan.length > 6) {
  throw new Error('[Build Scenes Prompt] scene_plan_json must contain 3 to 6 planned scenes.');
}

let packagingSection = '';
if (jobConfig.hook_line) {
  packagingSection += 'OPENING HOOK: ' + jobConfig.hook_line + '\n';
}
if (jobConfig.title_moment) {
  packagingSection += 'KEY MOMENT/REVEAL: ' + jobConfig.title_moment + '\n';
}
if (jobConfig.visual_moment_tags_summary) {
  packagingSection += 'VISUAL MOMENT TAGS: ' + jobConfig.visual_moment_tags_summary + '\n';
}
if (packagingSection) {
  packagingSection = '\nPACKAGING CUES (optional context for visual framing):\n' + packagingSection;
}

const dialogueContext = normalizedDialogue.map(function(segment) {
  return '[' + segment.segment_index + '] ' + segment.speaker + ': ' + segment.text;
}).join('\n');

const systemContent = config.prompt_canon_header;
let userTemplate = config.prompt_shorts_scenes;

const placeholders = {
  '{normalized_dialogue}': dialogueContext,
  '{scene_plan}': JSON.stringify(scenePlan, null, 2),
  '{estimated_duration_sec}': String(jobConfig.estimated_duration_sec || ''),
  '{word_count}': String(jobConfig.word_count || ''),
  '{packaging_cues}': packagingSection,
  '{scene_count}': String(scenePlan.length),
  '{hook_line}': jobConfig.hook_line || '',
  '{title_moment}': jobConfig.title_moment || '',
  '{visual_moment_tags_summary}': jobConfig.visual_moment_tags_summary || '',
  '{topic}': jobConfig.topic || '',
  '{angle}': jobConfig.angle || '',
  '{niche}': jobConfig.niche || ''
};

let userContent = userTemplate;
for (const [key, value] of Object.entries(placeholders)) {
  userContent = userContent.split(key).join(value);
}

return [{
  json: {
    topic: jobConfig.topic,
    angle: jobConfig.angle,
    niche: jobConfig.niche,
    topic_slug: jobConfig.topic_slug,
    scenes_filename: jobConfig.scenes_filename,
    normalized_dialogue_json: jobConfig.normalized_dialogue_json,
    scene_plan_json: jobConfig.scene_plan_json,
    estimated_duration_sec: jobConfig.estimated_duration_sec,
    word_count: jobConfig.word_count,
    openai_payload: {
      model: 'gpt-5.4-mini',
      temperature: Number(config.GPT_Temperature),
      max_completion_tokens: 1600,
      messages: [
        { role: 'system', content: systemContent },
        { role: 'user', content: userContent }
      ]
    }
  }
}];

// Build the OpenAI request payload for beat-aware image concept generation.
// system = prompt_canon_header; user = prompt_shorts_images with placeholder substitution.

const config = $('Code: Build Config').first().json;
const jobConfig = $('Code: Pick & Lock Job').first().json;

let normalizedDialogue;
let scenePlan;
try {
  normalizedDialogue = JSON.parse(String(jobConfig.normalized_dialogue_json || '[]'));
  scenePlan = JSON.parse(String(jobConfig.scene_plan_json || '[]'));
} catch (error) {
  throw new Error('[Build Images Prompt] Failed to parse normalized dialogue or scene plan: ' + error.message);
}

if (!Array.isArray(normalizedDialogue) || !normalizedDialogue.length) {
  throw new Error('[Build Images Prompt] normalized_dialogue_json is empty or invalid.');
}
if (!Array.isArray(scenePlan) || !scenePlan.length) {
  throw new Error('[Build Images Prompt] scene_plan_json is empty or invalid.');
}

const dialogueContext = normalizedDialogue.map(function(segment) {
  return '[' + segment.segment_index + '] ' + segment.speaker + ': ' + segment.text;
}).join('\n');

const plannedScenes = scenePlan.map(function(scene) {
  const relatedLines = scene.related_segment_indexes.map(function(index) {
    const segment = normalizedDialogue[index];
    return '[' + index + '] ' + segment.speaker + ': ' + segment.text;
  }).join(' | ');
  return {
    index: scene.index,
    beat_type: scene.beat_type,
    chapter_label: scene.chapter_label,
    related_segment_indexes: scene.related_segment_indexes,
    dialogue_excerpt: relatedLines,
    position: scene.position,
    bg_index: scene.bg_index,
    visual_change_required: scene.visual_change_required
  };
});

const exampleItem = JSON.stringify({
  index: 0,
  related_scene_index: 0,
  chapter_label: 'Setup',
  prompt: 'Split-screen host introducing a slang debate, expressive silhouettes, warm interior light, retro-meets-modern living room, medium 9:16 framing, high-contrast playful colors, faceless stylized characters',
  style_notes: 'Bold readable composition, shorts-friendly contrast, clean negative space for captions.',
  overlay_text: 'Wait, you say that?'
}, null, 2);

const systemContent = config.prompt_canon_header;
let userTemplate = config.prompt_shorts_images;

const placeholders = {
  '{normalized_dialogue}': dialogueContext,
  '{planned_scenes}': JSON.stringify(plannedScenes, null, 2),
  '{scene_count}': String(scenePlan.length),
  '{example_item}': exampleItem,
  '{topic}': jobConfig.topic || '',
  '{angle}': jobConfig.angle || '',
  '{niche}': jobConfig.niche || ''
};

let userContent = userTemplate;
for (const [key, value] of Object.entries(placeholders)) {
  userContent = userContent.split(key).join(value);
}

return [{
  json: {
    topic: jobConfig.topic,
    angle: jobConfig.angle,
    niche: jobConfig.niche,
    topic_slug: jobConfig.topic_slug,
    images_filename: jobConfig.images_filename || ((jobConfig.topic_slug || 'video') + '_images.json'),
    normalized_dialogue_json: jobConfig.normalized_dialogue_json,
    scene_plan_json: jobConfig.scene_plan_json,
    openai_payload: {
      model: 'gpt-5.4-mini',
      temperature: Number(config.GPT_Temperature),
      max_completion_tokens: 1800,
      messages: [
        { role: 'system', content: systemContent },
        { role: 'user', content: userContent }
      ]
    }
  }
}];

// Parse and validate beat-aware scenes generated from the dialogue-first scene plan.
const openAiItem = items[0].json;
const pickData = $('Code: Pick & Lock Job').first().json;

if (!pickData.topic_slug) throw new Error('Missing topic_slug from Pick & Lock Job');

let normalizedDialogue;
let scenePlan;
try {
  normalizedDialogue = JSON.parse(String(pickData.normalized_dialogue_json || '[]'));
  scenePlan = JSON.parse(String(pickData.scene_plan_json || '[]'));
} catch (error) {
  throw new Error('[Parse Scenes] Failed to parse normalized dialogue or scene plan: ' + error.message);
}

if (!Array.isArray(normalizedDialogue) || !normalizedDialogue.length) {
  throw new Error('[Parse Scenes] normalized_dialogue_json is empty or invalid.');
}
if (!Array.isArray(scenePlan) || scenePlan.length < 3 || scenePlan.length > 6) {
  throw new Error('[Parse Scenes] scene_plan_json must contain 3 to 6 scenes.');
}

const raw = (
  openAiItem?.choices?.[0]?.message?.content
  ?? openAiItem?.message?.content
  ?? openAiItem?.text
  ?? ''
).trim();
if (!raw) throw new Error('[Parse Scenes] Empty OpenAI scenes response');

let parsed;
try {
  const cleaned = raw.replace(/^```[\w]*[\r\n]+/, '').replace(/[\r\n]+```$/, '').trim();
  const obj = JSON.parse(cleaned);
  parsed = Array.isArray(obj) ? obj : (Array.isArray(obj?.scenes) ? obj.scenes : null);
} catch (err) {
  throw new Error('[Parse Scenes] Scenes JSON parse error: ' + err.message + '\n\nRaw (first 600): ' + raw.slice(0, 600));
}

if (!Array.isArray(parsed)) {
  throw new Error('[Parse Scenes] Expected a JSON array of scenes.');
}
if (parsed.length !== scenePlan.length || parsed.length < 3 || parsed.length > 6) {
  throw new Error('[Parse Scenes] Expected ' + scenePlan.length + ' scenes from the shared beat plan, got ' + parsed.length + '.');
}

const allowedBeatTypes = new Set(['host_transition', 'reaction_reply', 'same_speaker_continuation', 'payoff', 'topic_shift']);
const validSegmentIndexes = new Set(normalizedDialogue.map(function(segment) { return Number(segment.segment_index); }));

const normalized = parsed.map(function(scene, i) {
  if (!scene || Array.isArray(scene) || typeof scene !== 'object') {
    throw new Error('[Parse Scenes] Scene ' + i + ' must be an object.');
  }

  const plan = scenePlan[i];
  const index = Number(scene.index);
  if (!Number.isInteger(index) || index !== i) {
    throw new Error('[Parse Scenes] Scene ' + i + ' must have sequential index ' + i + '.');
  }

  if (!Array.isArray(scene.related_segment_indexes) || !scene.related_segment_indexes.length) {
    throw new Error('[Parse Scenes] Scene ' + i + ' must include a non-empty related_segment_indexes array.');
  }

  const relatedSegmentIndexes = scene.related_segment_indexes.map(function(value) {
    const numberValue = Number(value);
    if (!Number.isInteger(numberValue) || !validSegmentIndexes.has(numberValue)) {
      throw new Error('[Parse Scenes] Scene ' + i + ' references invalid related_segment_index ' + value + '.');
    }
    return numberValue;
  });

  if (JSON.stringify(relatedSegmentIndexes) !== JSON.stringify(plan.related_segment_indexes)) {
    throw new Error('[Parse Scenes] Scene ' + i + ' related_segment_indexes must match the shared beat plan.');
  }

  if (typeof scene.text !== 'string' || !scene.text.trim()) {
    throw new Error('[Parse Scenes] Scene ' + i + ' is missing non-empty text.');
  }

  const beatType = String(scene.beat_type || plan.beat_type || '').trim();
  if (!allowedBeatTypes.has(beatType)) {
    throw new Error('[Parse Scenes] Scene ' + i + ' has invalid beat_type: ' + beatType);
  }

  const position = String(scene.position || plan.position || '').trim() || 'bottom';
  const bgIndex = Number(scene.bg_index);
  if (!Number.isInteger(bgIndex)) {
    throw new Error('[Parse Scenes] Scene ' + i + ' has invalid bg_index.');
  }

  const allowedIntensities = new Set(['high', 'medium', 'low']);
  const allowedVisualPriorities = new Set(['speaker', 'text', 'split']);

  const rawSpeakerFocus = Array.isArray(scene.speaker_focus) ? scene.speaker_focus : (Array.isArray(plan.speaker_focus) ? plan.speaker_focus : []);
  const speakerFocus = rawSpeakerFocus.map(function(s) { return String(s || '').trim().toUpperCase(); }).filter(Boolean);

  const rawIntensity = String(scene.reaction_intensity || '').trim();
  const reactionIntensity = allowedIntensities.has(rawIntensity)
    ? rawIntensity
    : (allowedIntensities.has(String(plan.reaction_intensity || '').trim()) ? String(plan.reaction_intensity).trim() : 'medium');

  const rawVisualPriority = String(scene.visual_priority || '').trim();
  const visualPriority = allowedVisualPriorities.has(rawVisualPriority)
    ? rawVisualPriority
    : (allowedVisualPriorities.has(String(plan.visual_priority || '').trim()) ? String(plan.visual_priority).trim() : 'split');

  return {
    index,
    related_segment_indexes: relatedSegmentIndexes,
    beat_type: beatType,
    chapter_label: String(scene.chapter_label || plan.chapter_label || '').trim() || plan.chapter_label,
    text: scene.text.trim(),
    position,
    bg_index: bgIndex,
    visual_change_required: typeof scene.visual_change_required === 'boolean'
      ? scene.visual_change_required
      : Boolean(plan.visual_change_required),
    speaker_focus: speakerFocus,
    reaction_intensity: reactionIntensity,
    visual_priority: visualPriority
  };
});

const content = JSON.stringify(normalized, null, 2);
const buffer = Buffer.from(content, 'utf8');

return [{
  json: {
    job_id: pickData.job_id,
    topic_slug: pickData.topic_slug,
    scenes_filename: pickData.scenes_filename,
    scenes_json: JSON.stringify(normalized),
    normalized_dialogue_json: pickData.normalized_dialogue_json,
    scene_plan_json: pickData.scene_plan_json,
    scenes_state: 'READY',
    images_state: 'REQUESTED',
    lock_owner: '',
    lock_until: '',
    last_error: ''
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: pickData.scenes_filename,
      fileExtension: 'json'
    }
  }
}];

// Parse the OpenAI response for image concepts and validate them against the shared beat-based scene plan.
// Also creates binary file content for Google Drive upload.

const openAiItem = items[0].json;
const pickData = $('Code: Pick & Lock Job').first().json;

let scenePlan;
try {
  scenePlan = JSON.parse(String(pickData.scene_plan_json || '[]'));
} catch (error) {
  throw new Error('[Parse Images JSON] Failed to parse scene_plan_json: ' + error.message);
}

if (!Array.isArray(scenePlan) || !scenePlan.length) {
  throw new Error('[Parse Images JSON] scene_plan_json is empty or invalid.');
}

const validSceneIndexes = new Set(scenePlan.map(function(scene) { return Number(scene.index); }));
const sceneByIndex = Object.fromEntries(scenePlan.map(function(scene) { return [Number(scene.index), scene]; }));

const raw = (
  openAiItem?.choices?.[0]?.message?.content
  ?? openAiItem?.message?.content
  ?? openAiItem?.text
  ?? ''
).trim();

if (!raw) {
  throw new Error(
    '[Parse Images JSON] OpenAI returned empty content.\n' +
    'Check: (1) OpenAI API credential is valid, ' +
    '(2) your account has quota, ' +
    '(3) the HTTP Request node returned a 200 status.'
  );
}

let parsed;
try {
  const cleaned = raw
    .replace(/^```[\w]*[\r\n]+/, '')
    .replace(/[\r\n]+```$/, '')
    .trim();
  const obj = JSON.parse(cleaned);
  if (!Array.isArray(obj) && Array.isArray(obj?.images)) {
    parsed = obj.images;
  } else if (Array.isArray(obj)) {
    parsed = obj;
  } else {
    throw new Error('Expected { "images": [...] } or a bare array, got: ' + typeof obj);
  }
} catch (err) {
  throw new Error(
    '[Parse Images JSON] Could not parse LLM output as JSON.\n' +
    'Parse error: ' + err.message + '\n\n' +
    'Raw response (first 600 chars):\n' + raw.slice(0, 600)
  );
}

if (!Array.isArray(parsed) || parsed.length !== scenePlan.length) {
  throw new Error('[Parse Images JSON] Expected exactly ' + scenePlan.length + ' image concepts, got ' + (Array.isArray(parsed) ? parsed.length : typeof parsed));
}

const normalized = parsed.map(function(img, i) {
  if (!img || Array.isArray(img) || typeof img !== 'object') {
    throw new Error('[Parse Images JSON] Image[' + i + '] must be an object.');
  }

  const index = Number(img.index);
  if (!Number.isInteger(index) || index !== i) {
    throw new Error('[Parse Images JSON] Image[' + i + '] must have sequential index ' + i + '.');
  }

  const relatedSceneIndex = Number(img.related_scene_index);
  if (!Number.isInteger(relatedSceneIndex) || !validSceneIndexes.has(relatedSceneIndex)) {
    throw new Error('[Parse Images JSON] Image[' + i + '] has invalid related_scene_index: ' + img.related_scene_index);
  }

  if (typeof img.prompt !== 'string' || img.prompt.trim() === '') {
    throw new Error('[Parse Images JSON] Image[' + i + '] missing or invalid "prompt"');
  }
  if (typeof img.style_notes !== 'string' || img.style_notes.trim() === '') {
    throw new Error('[Parse Images JSON] Image[' + i + '] missing or invalid "style_notes"');
  }
  if (typeof img.overlay_text !== 'string') {
    throw new Error('[Parse Images JSON] Image[' + i + '] missing or invalid "overlay_text"');
  }

  const scene = sceneByIndex[relatedSceneIndex];
  return {
    index,
    related_scene_index: relatedSceneIndex,
    chapter_label: String(img.chapter_label || scene.chapter_label || '').trim() || scene.chapter_label,
    order_in_chapter: 1,
    suggested_time_range: { start: 0, end: 0 },
    prompt: img.prompt.trim(),
    style_notes: img.style_notes.trim(),
    overlay_text: img.overlay_text.trim()
  };
});

const topic = pickData.topic || 'unknown';
const slug = pickData.topic_slug || topic.toLowerCase().replace(/[^a-z0-9]+/g, '_').slice(0, 60);
const filename = pickData.images_filename || (slug + '_images.json');

const content = JSON.stringify({ images: normalized }, null, 2);
const buffer = Buffer.from(content, 'utf8');

return [{
  json: {
    topic: topic,
    topic_slug: slug,
    images_json: JSON.stringify({ images: normalized }),
    images_filename: filename,
    image_count: normalized.length,
    images_created_at: new Date().toISOString()
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: filename,
      fileExtension: 'json'
    }
  }
}];

const scenesData = $('Code: Parse Scenes').first().json;
const imagesData = $('Code: Parse Images').first().json;
const scenesDrive = $('Drive: Upload scenes.json').first().json;
const job = $('Code: Pick & Lock Job').first().json;

let beatsJson = '[]';
try {
  const scenes = JSON.parse(scenesData.scenes_json || '[]');
  const beats = scenes.map(function(s) {
    return {
      beat_index: s.index,
      beat_type: s.beat_type,
      speaker_focus: Array.isArray(s.speaker_focus) ? s.speaker_focus : [],
      reaction_intensity: s.reaction_intensity || 'medium',
      visual_priority: s.visual_priority || 'split',
      chapter_label: s.chapter_label || '',
      related_segment_indexes: Array.isArray(s.related_segment_indexes) ? s.related_segment_indexes : []
    };
  });
  beatsJson = JSON.stringify(beats);
} catch (e) { beatsJson = '[]'; }

return [{ json: {
  job_id: job.job_id,
  scenes_state: 'READY',
  images_state: 'REQUESTED',
  scenes_file_id: scenesDrive.id || '',
  scenes_json: scenesData.scenes_json || '[]',
  images_json: imagesData.images_json || '{"images":[]}',
  beats_json: beatsJson,
  lock_owner: '',
  lock_until: '',
  last_error: ''
} }];

const cfg = {};
for (const item of items) {
  const name  = (item.json.Name  ?? '').trim();
  const value = item.json.Value;
  if (name && value != null && value !== '') {
    cfg[name] = value;
  }
}
const required = ['OpenAI_ApiKey', 'prompt_canon_header', 'prompt_shorts_scenes', 'prompt_shorts_images', 'Scenes', 'Images', 'GPT_Temperature'];
for (const key of required) {
  if (!cfg[key]) {
    throw new Error('[Build Config] Missing required key: ' + key + '. Add it to EnvironmentVariables table.');
  }
}
return [{ json: cfg }];
